import{_ as l,c as e,a2 as t,o as i}from"./chunks/framework.YPpNXepj.js";const p=JSON.parse('{"title":"网络代理","description":"","frontmatter":{},"headers":[],"relativePath":"note/network.md","filePath":"note/network.md","lastUpdated":null}'),r={name:"note/network.md"};function o(n,a,s,d,c,u){return i(),e("div",null,a[0]||(a[0]=[t('<h1 id="网络代理" tabindex="-1">网络代理 <a class="header-anchor" href="#网络代理" aria-label="Permalink to &quot;网络代理&quot;">​</a></h1><ul><li>网络代理 (Proxy) 是一种网络服务, 允许一个网络终端（通常是客户端）通过这个服务器(代理服务器)与另一个网络终端（通常是服务器）进行<strong>非直接的连接</strong>, 充当中介角色.</li><li>代理方式</li><li>目的功能: 隐藏客户端的真实IP地址, 访问控制与过滤, 内容缓存提高访问速度, 绕过地域限制</li><li>代理服务器根据其功能和用途可以分为多种类型，包括： <ul><li>HTTP代理：用于浏览网页和下载数据。</li><li>SOCKS代理：一种通用代理，适用于多种协议。</li><li>VPN代理：通过加密通道建立专用网络，确保数据传输的安全性。</li><li>反向代理：通常部署在服务器端，用于负载均衡、缓存静态内容等。</li></ul></li><li>注意选择安全可靠的代理服务，并遵守当地法律法规</li><li>在中国，使用代理访问国际网站在法律上并不明确禁止，但需遵守当地的相关法律法规。在使用代理时，请确保不进行违法活动。</li></ul><h1 id="vpn" tabindex="-1">VPN <a class="header-anchor" href="#vpn" aria-label="Permalink to &quot;VPN&quot;">​</a></h1><ul><li>VPN（虚拟私人网络）是一种通过公共网络（如互联网）建立加密连接的技术, 主要用于保护用户的数据传输安全和隐私.</li><li>VPN 属于代理服务器的一种形式，但两者在功能和工作原理上存在显著区别, 具备额外的加密功能.</li></ul><h1 id="梯子" tabindex="-1">梯子 <a class="header-anchor" href="#梯子" aria-label="Permalink to &quot;梯子&quot;">​</a></h1>',5)]))}const P=l(r,[["render",o]]);export{p as __pageData,P as default};
